"use client";

import { FormEvent, useState } from "react";
import { Briefcase, FileCheck2, ShieldCheck } from "lucide-react";
import PageHero from "@/components/PageHero";
import SectionReveal from "@/components/SectionReveal";
import styles from "./page.module.css";

type SubmitState = "idle" | "success" | "error";

export default function CareersPage() {
  const [state, setState] = useState<SubmitState>("idle");
  const [submitting, setSubmitting] = useState(false);

  async function onSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const form = event.currentTarget;
    const formData = new FormData(form);

    if ((formData.get("website") as string)?.length) {
      return;
    }

    setSubmitting(true);
    setState("idle");

    try {
      const response = await fetch("/api/careers", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) {
        throw new Error("Submit failed");
      }

      setState("success");
      form.reset();
    } catch {
      setState("error");
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <>
      <PageHero
        title="Careers"
        subtitle="Join a compassionate team focused on safe, dependable patient transportation."
        breadcrumb="Careers"
      />

      <section className="section">
        <div className={`container ${styles.layout}`}>
          <SectionReveal className={styles.leftCol}>
            <h2>Build a Meaningful Career</h2>
            <p>
              We are looking for professionals who combine strong technical safety
              standards with empathetic patient care.
            </p>

            <div className={styles.blocks}>
              <article className={`card ${styles.block}`}>
                <h3>
                  <ShieldCheck size={18} /> Minimum Qualifications
                </h3>
                <ul>
                  <li>Valid Ontario G class license and clean abstract</li>
                  <li>Current CPR or BLS certification</li>
                  <li>Safe patient handling and communication skills</li>
                  <li>Vulnerable sector check eligibility</li>
                </ul>
              </article>

              <article className={`card ${styles.block}`}>
                <h3>
                  <FileCheck2 size={18} /> Preferred Experience
                </h3>
                <ul>
                  <li>Medical transport, EMS, or care facility support background</li>
                  <li>Wheelchair and stretcher transfer familiarity</li>
                  <li>Strong attention to patient dignity and documentation</li>
                </ul>
              </article>
            </div>
          </SectionReveal>

          <SectionReveal className={`card ${styles.formCard}`} delay={80}>
            <h3>
              <Briefcase size={18} /> Apply Now
            </h3>
            <p>Upload your resume in PDF, DOC, or DOCX format.</p>

            {state === "success" && (
              <p className={styles.success}>Application submitted successfully.</p>
            )}
            {state === "error" && (
              <p className={styles.error}>Could not submit application. Try again.</p>
            )}

            <form className={styles.form} onSubmit={onSubmit} encType="multipart/form-data">
              <input name="website" autoComplete="off" tabIndex={-1} className={styles.honeypot} />

              <label>
                Full Name
                <input name="name" required />
              </label>

              <label>
                Phone
                <input name="phone" type="tel" required />
              </label>

              <label>
                Email
                <input name="email" type="email" required />
              </label>

              <label>
                Certifications
                <textarea
                  name="certifications"
                  rows={4}
                  placeholder="List BLS, CPR, patient transfer, or related certifications"
                />
              </label>

              <label>
                Resume
                <input name="resume" type="file" accept=".pdf,.doc,.docx" required />
              </label>

              <button type="submit" className="btn btn-primary btn-pill" disabled={submitting}>
                {submitting ? "Submitting..." : "Submit Application"}
              </button>
            </form>
          </SectionReveal>
        </div>
      </section>
    </>
  );
}
